COPY public.assessment_response_history (id, response_id, response_data, computed_score, computed_score_label, status, changed_by, changed_at, change_type, review_round, reviewer_feedback, evidence_snapshot) FROM stdin;
9b936d31-31e3-4fc8-a2de-a190a8904c91	ef156163-ebdd-4209-b046-908b27599f54	{"doc_signed": false, "doc_approved": true, "ai_assessment": {"confidence": 100, "justification": "The control requires evidence of a 'Training Session Report' detailing specific elements: dates, attendees, materials, objectives, and topics. The supporting document, 'od_m1_evidence.docx', is an 'Open Dataset List' and discusses data governance and inventory management. This document fails to provide any evidence regarding the scheduling, participation, content, or objectives of any training sessions. Consequently, the acceptance criteria for R2.1 are not met.", "_ai_product_id": "26148612-c82e-4529-846e-91dadb24f48a", "recommendations": "To achieve compliance, evidence must be provided in the form of formal, dated, and approved training session reports. These reports must explicitly contain detailed logs covering the dates, a list of attendees, documentation of materials used, and clear articulation of the objectives and topics covered for each training instance.", "review_feedback": "The evidence provided pertains to the inventory and status of open datasets, which is unrelated to the control requirement for documenting training sessions. The documentation reviewed details data assets and their publication status, rather than records of training activities.\\n\\nThe acceptance criteria mandate detailed logs including session dates, attendee lists, materials used, and specific objectives/topics. The evidence reviewed does not contain any information corresponding to these required training records.\\n\\nTo demonstrate compliance, evidence must directly address the lifecycle and documentation of training sessions conducted for the AI product.", "compliance_status": "Non-Compliant", "document_analysis": [{"notes": "Document is dated and marked as 'Approved' (معتمد), but lacks explicit signatures.", "file_name": "od_m1_evidence.docx", "approved_by": null, "is_approved": true, "document_date": "2025-01-15", "has_signature": false}]}, "justification": "The control requires evidence of a 'Training Session Report' detailing specific elements: dates, attendees, materials, objectives, and topics. The supporting document, 'od_m1_evidence.docx', is an 'Open Dataset List' and discusses data governance and inventory management. This document fails to provide any evidence regarding the scheduling, participation, content, or objectives of any training sessions. Consequently, the acceptance criteria for R2.1 are not met.", "recommendation": "To achieve compliance, evidence must be provided in the form of formal, dated, and approved training session reports. These reports must explicitly contain detailed logs covering the dates, a list of attendees, documentation of materials used, and clear articulation of the objectives and topics covered for each training instance.", "review_feedback": "The evidence provided pertains to the inventory and status of open datasets, which is unrelated to the control requirement for documenting training sessions. The documentation reviewed details data assets and their publication status, rather than records of training activities.\\n\\nThe acceptance criteria mandate detailed logs including session dates, attendee lists, materials used, and specific objectives/topics. The evidence reviewed does not contain any information corresponding to these required training records.\\n\\nTo demonstrate compliance, evidence must directly address the lifecycle and documentation of training sessions conducted for the AI product.", "compliance_status": "Non-Compliant"}	2.00	Non-Compliant	answered	e711b119-d9bf-4b40-9553-be7d9acf7fa7	2026-04-11 19:40:15.715527+00	status_change	0	The evidence provided pertains to the inventory and status of open datasets, which is unrelated to the control requirement for documenting training sessions. The documentation reviewed details data assets and their publication status, rather than records of training activities.\n\nThe acceptance criteria mandate detailed logs including session dates, attendee lists, materials used, and specific objectives/topics. The evidence reviewed does not contain any information corresponding to these required training records.\n\nTo demonstrate compliance, evidence must directly address the lifecycle and documentation of training sessions conducted for the AI product.	[{"id": "f21660c9-213a-4b18-b7bc-fb664a564647", "file_name": "od_m1_evidence.docx", "file_size": 10672}]
a148cba3-68b0-48ac-98a8-3b34f2b393ce	dc93ac92-b9ac-4c87-a607-8761916b24b3	{"doc_signed": false, "doc_approved": false, "ai_assessment": {"confidence": 80, "justification": "The evidence document 'od_c11_open_data_plan.docx' does not provide any records that trace decisions back to their data sources and algorithms as per the requirement. It outlines a general framework for managing and publishing open data, which is unrelated to internal audit logs. The document lacks timestamps, data points used, and intermediate processing steps necessary for compliance with R1.5.", "_ai_product_id": "26148612-c82e-4529-846e-91dadb24f48a", "recommendations": "The entity should prepare an internal audit log system that records all decisions related to the chatbot's operations, including the data sources and algorithms involved. This system should include detailed timestamps, data points, and intermediate processing steps to ensure traceability.", "review_feedback": "The provided document does not address the specific control requirement related to internal audit logs for tracing decisions back to their data sources and algorithms. The document focuses on an open data plan, which is unrelated to the internal audit logs required by the control.", "compliance_status": "Non-Compliant", "document_analysis": [{"notes": "The document is not dated, lacks formal approval, and does not contain any signatures or stamps. It focuses on an open data plan rather than internal audit logs.", "file_name": "od_c11_open_data_plan.docx", "approved_by": null, "is_approved": false, "document_date": null, "has_signature": false}]}, "justification": "The evidence document 'od_c11_open_data_plan.docx' does not provide any records that trace decisions back to their data sources and algorithms as per the requirement. It outlines a general framework for managing and publishing open data, which is unrelated to internal audit logs. The document lacks timestamps, data points used, and intermediate processing steps necessary for compliance with R1.5.", "recommendation": "The entity should prepare an internal audit log system that records all decisions related to the chatbot's operations, including the data sources and algorithms involved. This system should include detailed timestamps, data points, and intermediate processing steps to ensure traceability.", "review_feedback": "The provided document does not address the specific control requirement related to internal audit logs for tracing decisions back to their data sources and algorithms. The document focuses on an open data plan, which is unrelated to the internal audit logs required by the control.", "compliance_status": "Compliant"}	0.00	Compliant	draft	e711b119-d9bf-4b40-9553-be7d9acf7fa7	2026-04-12 09:01:38.180266+00	score_change	0	The provided document does not address the specific control requirement related to internal audit logs for tracing decisions back to their data sources and algorithms. The document focuses on an open data plan, which is unrelated to the internal audit logs required by the control.	[{"id": "47706c23-61c8-44c6-92dd-f8557449fc96", "file_name": "MOTLS_Chatbot_AC_Compliant.docx", "file_size": 12874}]
